18	const PUBLIC_LINKS: { href: string; label: string; badge?: string }[] = [
19	  { href: "/", label: "Home" },
20	  { href: "/about", label: "About" },
21	  { href: "/development", label: "Development" },
22	  { href: "/investments", label: "Investments" },
23	  { href: "/systems", label: "Systems" },
24	  { href: "/marketflow-beta", label: "MarketFlow Beta", badge: "Beta" },
25	  { href: "/contact", label: "Contact" },
