28	function isAppShellRoute(pathname: string): boolean {
29	  return (
30	    pathname === "/marketflow" ||
31	    pathname.startsWith("/marketflow/") ||
32	    pathname.startsWith("/dealflow") ||
33	    pathname.startsWith("/marketplace") ||
34	    pathname.startsWith("/portal") ||
35	    pathname.startsWith("/dashboard") ||
36	    pathname.startsWith("/offer-studio") ||
37	    pathname.startsWith("/profile") ||
38	    pathname.startsWith("/login") ||
39	    pathname.startsWith("/signup") ||
40	    pathname === "/hq"
41	  );
42	}
43	
44	function isActive(current: string, href: string): boolean {
45	  if (href === "/") return current === "/";
46	  return current === href || current.startsWith(href + "/");
47	}
48	
49	function UserMenu() {
50	  const { user, profile, isAdmin } = useSupabaseAuth();
51	  const displayName = profile?.display_name || "Member";
52	  const initials = displayName
53	    .split(" ")
54	    .map((p: string) => p[0])
55	    .join("")
56	    .slice(0, 2)
57	    .toUpperCase();
58	
59	  return (
60	    <DropdownMenu>
61	      <DropdownMenuTrigger asChild>
62	        <button
63	          className="flex items-center gap-2 rounded-full border border-border bg-background px-2 py-1.5 text-sm transition hover:border-primary/40 hover:bg-muted"
64	          data-testid="button-user-menu"
65	        >
66	          <Avatar className="h-7 w-7">
67	            <AvatarImage src={profile?.avatar_url} />
68	            <AvatarFallback className="bg-primary/10 text-primary text-[11px] font-semibold">
69	              {initials}
70	            </AvatarFallback>
71	          </Avatar>
72	          <ChevronDown className="h-3.5 w-3.5 text-muted-foreground" />
73	        </button>
74	      </DropdownMenuTrigger>
75	      <DropdownMenuContent align="end" className="w-56">
76	        <DropdownMenuLabel>
77	          <p className="text-sm font-medium">{displayName}</p>
78	          <p className="truncate text-xs text-muted-foreground">{user?.email}</p>
79	        </DropdownMenuLabel>
80	        <DropdownMenuSeparator />
81	        <Link href="/marketflow">
82	          <DropdownMenuItem className="gap-2 cursor-pointer">
83	            <Sparkles className="h-4 w-4" />
84	            MarketFlow
85	          </DropdownMenuItem>
86	        </Link>
87	        <Link href="/marketflow/dashboard">
88	          <DropdownMenuItem className="gap-2 cursor-pointer">
89	            <BarChart3 className="h-4 w-4" />
90	            Dashboard
91	          </DropdownMenuItem>
92	        </Link>
93	        {isAdmin && (
94	          <Link href="/marketflow/admin">
95	            <DropdownMenuItem className="gap-2 cursor-pointer">
96	              <Shield className="h-4 w-4" />
97	              Admin
98	            </DropdownMenuItem>
99	          </Link>
100	        )}
101	        <DropdownMenuSeparator />
102	        <a href="/api/logout">
103	          <DropdownMenuItem className="gap-2 cursor-pointer text-destructive focus:text-destructive">
104	            <LogOut className="h-4 w-4" />
105	            Sign out
106	          </DropdownMenuItem>
107	        </a>
108	      </DropdownMenuContent>
109	    </DropdownMenu>
110	  );
111	}
