113	export function Navigation() {
114	  const [open, setOpen] = useState(false);
115	  const [scrolled, setScrolled] = useState(false);
116	  const [location] = useLocation();
117	  const { isAuthenticated } = useSupabaseAuth();
118	
119	  useEffect(() => {
120	    const onScroll = () => setScrolled(window.scrollY > 12);
121	    onScroll();
122	    window.addEventListener("scroll", onScroll, { passive: true });
123	    return () => window.removeEventListener("scroll", onScroll);
124	  }, []);
125	
126	  useEffect(() => {
127	    setOpen(false);
128	  }, [location]);
129	
130	  const onAppShell = isAppShellRoute(location);
131	
132	  return (
133	    <header className="fixed inset-x-0 top-0 z-50">
134	      <div
135	        className={`transition-all duration-300 ${
136	          scrolled || onAppShell
137	            ? "bg-background/95 backdrop-blur-md border-b border-border shadow-sm"
138	            : "bg-background/80 backdrop-blur-sm border-b border-border/40"
139	        }`}
140	      >
141	        <div className="max-w-7xl mx-auto px-6 lg:px-12 flex h-16 items-center justify-between gap-6">
142	          {/* Logo */}
143	          <Link href="/" className="flex-shrink-0" data-testid="link-nav-logo">
144	            <img
145	              src={logoImage}
146	              alt="Pegasus Dreamscapes"
147	              className="h-10 w-auto"
148	            />
149	          </Link>
150	
151	          {/* Desktop nav */}
152	          <nav className="hidden lg:flex items-center gap-1">
153	            {PUBLIC_LINKS.map((link) => {
154	              const active = isActive(location, link.href);
155	              return (
156	                <Link
157	                  key={link.href}
158	                  href={link.href}
159	                  data-testid={`link-nav-${link.label.toLowerCase().replace(/\s+/g, "-")}`}
160	                  className={`relative px-3 py-2 text-sm font-medium rounded-md transition-colors ${
161	                    active
162	                      ? "text-primary bg-primary/8"
163	                      : "text-foreground/70 hover:text-foreground hover:bg-muted"
164	                  }`}
165	                >
166	                  <span className="inline-flex items-center gap-1.5">
167	                    {link.label}
168	                    {link.badge && (
169	                      <span className="rounded px-1.5 py-0.5 text-[9px] font-semibold uppercase tracking-wider bg-primary/10 text-primary">
170	                        {link.badge}
171	                      </span>
172	                    )}
173	                  </span>
174	                </Link>
175	              );
176	            })}
177	          </nav>
178	
179	          {/* Right cluster */}
180	          <div className="flex items-center gap-2">
181	            <Link
182	              href="/sell"
183	              className="hidden md:inline-flex items-center gap-1.5 rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition hover:bg-primary/90"
184	              data-testid="button-nav-submit"
185	            >
186	              Submit a Property
187	              <ArrowUpRight className="h-3.5 w-3.5" />
188	            </Link>
189	
190	            {isAuthenticated ? (
191	              <UserMenu />
192	            ) : (
193	              <a
194	                href="/api/login"
195	                className="hidden lg:inline-flex items-center gap-1.5 rounded-md px-3 py-2 text-sm font-medium text-foreground/70 transition hover:text-foreground hover:bg-muted"
196	                data-testid="link-nav-signin"
197	              >
198	                <LogIn className="h-4 w-4" />
199	                Sign In
200	              </a>
201	            )}
202	
203	            {/* Mobile toggle */}
204	            <button
205	              onClick={() => setOpen((v) => !v)}
206	              className="lg:hidden inline-flex h-9 w-9 items-center justify-center rounded-md border border-border text-foreground transition hover:bg-muted"
207	              aria-label={open ? "Close menu" : "Open menu"}
208	              aria-expanded={open}
209	              data-testid="button-mobile-menu"
210	            >
211	              {open ? <X className="h-4 w-4" /> : <Menu className="h-4 w-4" />}
212	            </button>
213	          </div>
214	        </div>
215	      </div>
216	
217	      {/* Mobile sheet */}
218	      <AnimatePresence>
219	        {open && (
220	          <motion.div
221	            initial={{ opacity: 0, y: -8 }}
222	            animate={{ opacity: 1, y: 0 }}
223	            exit={{ opacity: 0, y: -8 }}
224	            transition={{ duration: 0.15 }}
225	            className="lg:hidden bg-background border-b border-border shadow-md"
226	          >
227	            <div className="max-w-7xl mx-auto px-6 py-4">
228	              <div className="flex flex-col gap-1">
229	                {PUBLIC_LINKS.map((link) => {
230	                  const active = isActive(location, link.href);
231	                  return (
232	                    <Link
233	                      key={link.href}
234	                      href={link.href}
235	                      className={`flex items-center justify-between rounded-md px-3 py-3 text-sm font-medium transition ${
236	                        active
237	                          ? "bg-primary/10 text-primary"
238	                          : "text-foreground/80 hover:text-foreground hover:bg-muted"
239	                      }`}
240	                      data-testid={`link-mobile-${link.label.toLowerCase().replace(/\s+/g, "-")}`}
241	                    >
242	                      <span className="inline-flex items-center gap-2">
243	                        {link.label}
244	                        {link.badge && (
245	                          <span className="rounded px-1.5 py-0.5 text-[9px] font-semibold uppercase tracking-wider bg-primary/10 text-primary">
246	                            {link.badge}
247	                          </span>
248	                        )}
249	                      </span>
250	                      <ArrowUpRight className="h-3.5 w-3.5 opacity-40" />
251	                    </Link>
252	                  );
253	                })}
254	                <div className="mt-3 pt-3 border-t border-border flex flex-col gap-2">
255	                  <Link
256	                    href="/sell"
257	                    className="rounded-md bg-primary px-4 py-2.5 text-sm font-medium text-center text-primary-foreground transition hover:bg-primary/90"
258	                  >
259	                    Submit a Property
260	                  </Link>
261	                  {!isAuthenticated && (
262	                    <a
263	                      href="/api/login"
264	                      className="rounded-md border border-border px-4 py-2.5 text-sm font-medium text-center text-foreground/80 transition hover:bg-muted"
265	                    >
266	                      Sign In
267	                    </a>
268	                  )}
269	                </div>
270	              </div>
271	            </div>
272	          </motion.div>
273	        )}
274	      </AnimatePresence>
275	    </header>
276	  );
277	}
