217	/**
218	 * Using the elevate system.
219	 * Automatic contrast adjustment.
220	 *
221	 * <element className="hover-elevate" />
222	 * <element className="active-elevate-2" />
223	 *
224	 * // Using the tailwind utility when a data attribute is "on"
225	 * <element className="toggle-elevate data-[state=on]:toggle-elevated" />
226	 * // Or manually controlling the toggle state
227	 * <element className="toggle-elevate toggle-elevated" />
228	 *
229	 * Elevation systems have to handle many states.
230	 * - not-hovered, vs. hovered vs. active  (three mutually exclusive states)
231	 * - toggled or not
232	 * - focused or not (this is not handled with these utilities)
233	 *
234	 * Even without handling focused or not, this is six possible combinations that
235	 * need to be distinguished from eachother visually.
236	 */
237	@layer utilities {
238	
239	  /* Hide ugly search cancel button in Chrome until we can style it properly */
240	  input[type="search"]::-webkit-search-cancel-button {
241	    @apply hidden;
242	  }
243	
244	  /* Placeholder styling for contentEditable div */
245	  [contenteditable][data-placeholder]:empty::before {
246	    content: attr(data-placeholder);
247	    color: hsl(var(--muted-foreground));
248	    pointer-events: none;
249	  }
